from sympy import Abs, Function, atan2, cos, exp, log, sin
from sympy.physics import units
from sympy.physics.units.systems.si import SI
from sympy.physics.units import Quantity
from sympy.physics.units.definitions.dimension_definitions import angle, capacitance, impedance, time

D = SI.get_dimension_system()
exprs = {
    'derived ratio': units.second/(units.ohm*units.farad),
    'same quantity ratio': units.meter/units.meter,
    'same dimension ratio': units.meter/units.kilometer,
    'dimensional': units.second,
    'angle unit': units.radian,
}
funcs = [exp, sin, cos, log, Abs, Function('f')]
for label, arg in exprs.items():
    af, ad = SI._collect_factor_and_dimension(arg)
    print('\\nARG', label, repr(arg), '=>', repr(af), repr(ad), 'dimensionless=', D.is_dimensionless(ad))
    for fn in funcs:
        try:
            value = fn(arg, evaluate=False) if fn is Abs else fn(arg)
            result = SI._collect_factor_and_dimension(value)
            print(fn, repr(value), '=>', repr(result), 'dimless=', D.is_dimensionless(result[1]))
        except Exception as exc:
            print(fn, 'ERROR', type(exc).__name__, exc)

arg = units.second/(units.ohm*units.farad)
for fn in funcs:
    try:
        value = fn(arg, evaluate=False) if fn is Abs else fn(arg)
        print('ADD', fn, '=>', SI._collect_factor_and_dimension(100 + value))
    except Exception as exc:
        print('ADD', fn, 'ERROR', type(exc).__name__, exc)

for value in [atan2(units.meter, units.meter), atan2(arg, arg), log(arg, arg)]:
    try:
        print('MULTI', repr(value), 'args=', value.args, '=>', SI._collect_factor_and_dimension(value))
    except Exception as exc:
        print('MULTI', repr(value), 'ERROR', type(exc).__name__, exc)
PY"

